PropsTrigger = class("BaseProps")

PropsTrigger.TargetType = {
    Self = 0,
    Tower = 1,
    Monster = 2,
}

PropsTrigger.TargetRange = {
    Self = 1,
    All = 2,
}

function PropsTrigger:ctor(mapManager)
    self.map = mapManager
end

function PropsTrigger:useProps(propsId, userId)
    local config = PropsConfig:getConfigById(tonumber(propsId))
    if config then
        self:addBuff(config.buffId, config.targetType, config.targetRange, userId)
        self:stopMonster(config.stopDuration, config.targetRange, userId)
        self:addHp(config.addHp)
    end
end

function PropsTrigger:addBuff(buffId, targetType, targetRange, userId)
    local function getTargets(mapManager, targetType, targetRange, userId)
        if targetType == PropsTrigger.TargetType.Monster then
            if targetRange == PropsTrigger.TargetRange.Self then
                return LuaEntityManager:getMonstersByManager(mapManager, userId)
            else
                return LuaEntityManager:getMonstersByManager(mapManager)
            end
        end
        if targetType == PropsTrigger.TargetType.Tower then
            if targetRange == PropsTrigger.TargetRange.Self then
                return LuaEntityManager:getTowersByManager(mapManager, userId)
            else
                return LuaEntityManager:getTowersByManager(mapManager)
            end
        end
        return {}
    end
    local buffConfig = BuffConfig:getConfigById(buffId)
    if buffConfig then
        --获取目标
        local targets = getTargets(self.map, targetType, targetRange, userId)
        for _, target in pairs(targets) do
            GameBuff.new(target, buffId, userId)
        end
    end
end

--暂停出怪
function PropsTrigger:stopMonster(duration, targetRange, userId)
    if isClient then
        return
    end
    local function getPaths(mapManager, targetRange, userId)
        if targetRange == PropsTrigger.TargetRange.Self then
            for _, path in pairs(mapManager.pathList) do
                for _, pUserId in pairs(path.protectUserId) do
                    if tostring(pUserId) == tostring(userId) then
                        return { path }
                    end
                end
            end
        else
            return mapManager.pathList
        end
    end
    for _, path in pairs(getPaths(self.map, targetRange, userId) or {}) do
        path:stopMonster(duration)
    end
end

--增加血量
function PropsTrigger:addHp(count)
    if isClient then
        return
    end
    self.map:addHp(count)
end
